module priority_encoder(
	input [7:0] input_data,
	output reg [2:0] encoded_out
);
always @(*) begin
	if (input_data[7])
		encoded_out = 3'b111;
	else if (input_data[6])
		encoded_out = 3'b110;
	else if (input_data[5])
		encoded_out = 3'b101;
	else if (input_data[4])
		encoded_out = 3'b100;
	else if (input_data[3])
		encoded_out = 3'b011;
	else if (input_data[2])
		encoded_out = 3'b010;
	else if (input_data[1])
		encoded_out = 3'b001;
	else if (input_data[0])
		encoded_out = 3'b000;
	else
		encoded_out = 3'b000;
end
endmodule
